BEGIN;
CREATE TABLE market.news_sources(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),source_key text UNIQUE NOT NULL,name text NOT NULL,source_type text NOT NULL,status text NOT NULL,config jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.news_headlines(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),source_id uuid REFERENCES market.news_sources(id) ON DELETE SET NULL,headline text NOT NULL,category text NOT NULL,sentiment text NOT NULL,impact text NOT NULL,published_at timestamptz NOT NULL,metadata jsonb NOT NULL DEFAULT '{}'::jsonb);
CREATE TABLE market.news_sentiment_scores(observed_at timestamptz NOT NULL DEFAULT now(),id uuid NOT NULL DEFAULT gen_random_uuid(),score numeric(7,4) NOT NULL,mode text NOT NULL,asset_scores jsonb NOT NULL DEFAULT '{}'::jsonb,PRIMARY KEY(observed_at,id));
CREATE TABLE market.news_asset_impact(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),headline_id uuid REFERENCES market.news_headlines(id) ON DELETE CASCADE,symbol text NOT NULL,risk_level text NOT NULL,trading_permission text NOT NULL,notes text);
CREATE TABLE market.news_risk_events(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),headline_id uuid REFERENCES market.news_headlines(id) ON DELETE SET NULL,risk_level text NOT NULL,restriction_window text,recommendation text NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.news_classification_logs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),headline_id uuid REFERENCES market.news_headlines(id) ON DELETE CASCADE,classification jsonb NOT NULL,confidence numeric(7,4) NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.sentiment_snapshots(observed_at timestamptz NOT NULL DEFAULT now(),id uuid NOT NULL DEFAULT gen_random_uuid(),sentiment_score numeric(7,4) NOT NULL,sentiment_mode text NOT NULL,news_risk_mode text NOT NULL,workflow_permission text NOT NULL,PRIMARY KEY(observed_at,id));
CREATE TABLE market.sentiment_source_health(observed_at timestamptz NOT NULL DEFAULT now(),id uuid NOT NULL DEFAULT gen_random_uuid(),source_id uuid NOT NULL REFERENCES market.news_sources(id) ON DELETE CASCADE,status text NOT NULL,latency_ms integer,health_score numeric(7,4),PRIMARY KEY(observed_at,id));
COMMIT;
